    self.freePriceAdapt:setItemSize(freeWight, freeWight)
    self.lvFreeList:setAdapter(self.freePriceAdapt)
    self.lvFreeList.offset = 0
    self.lvFreeList.root:registerScrollEvent(GUIEvent.ScrollMoveChange, function(event)
        if self.lvFreeList.offset == event.offset then
