function UILicenseGrandPriceDisplay:onShow()
    if GUILicense.hadBuy > 0 then
        self.btnBuy:SetVisible(false)
    end
end

function UILicenseGrandPriceDisplay:setItemData(season)
    local freePriceConfigs = LicenseConfig:getGrandPriceConfigBySeason(season, 1)
    local payPriceConfig = LicenseConfig:getGrandPriceConfigBySeason(season, 2)

    self.freePriceAdapt:setData(freePriceConfigs)
    self.payPriceAdapt:setData(payPriceConfig)
end

function UILicenseGrandPriceDisplay:onLongClick(index, rewardType, describe)
    self.gvDescribe:setVisible(true)
    local curFreeOffset = self.lvFreeList.root:GetScrollOffset()
    local curPayOffset = self.lvPayList.root:GetScrollOffset()
    local height = self.lvFreeList:getHeight()
    if rewardType == 2 then
        self.gvDescribe:onDataChange(describe)
        local area = self.llPayList:GetArea()
        local describeX = index * height + 94 - height + (index - 1) * 28 + curPayOffset
        self.gvDescribe.root:SetXPosition({ 0, describeX })
        self.gvDescribe.root:SetYPosition({ area.min.y[1], -self.gvDescribe.root:GetPixelSize().y })
    else
        self.gvDescribe:onDataChange(describe)
        local area = self.llFreeList:GetArea()
        local describeX = index * height + 94 - height + (index - 1) * 28 + curFreeOffset
        self.gvDescribe.root:SetXPosition({ 0, describeX })
        self.gvDescribe.root:SetYPosition({ area.min.y[1], -self.gvDescribe.root:GetPixelSize().y })
    end
end

function UILicenseGrandPriceDisplay:onLongClickEnd()
    self.gvDescribe:setVisible(false)
end

return UILicenseGrandPriceDisplay